sql:
SELECT interval_id, total_emissions_kg
FROM emission_metrics
WHERE interval_id = 1;

SELECT ps.site_name, hp.hydrogen_production_kg_per_mw
FROM production_sites ps
JOIN hydrogen_production hp ON ps.site_id = hp.site_id;

SELECT site_name, capacity_mwh
FROM production_sites
WHERE capacity_mwh > 100;

SELECT site_name, AVG(capacity_mwh) AS average_capacity_mwh
FROM production_sites
GROUP BY site_name;

SELECT AVG(hydrogen_production_kg_per_mw) AS average_hydrogen_production_per_mw
FROM hydrogen_production
WHERE interval_id BETWEEN 1 AND 100;

SELECT site_id, AVG(hydrogen_production_kg_per_mw) AS average_hydrogen_production_per_mw
FROM hydrogen_production
GROUP BY site_id;

SELECT COUNT(*) 
FROM production_sites 
WHERE status = 'active';

SELECT AVG(normalized_electrolyzer_power * hydrogen_production_kg_per_mw) AS avg_hydrogen_per_mw
FROM hydrogen_production
WHERE interval_id BETWEEN 1 AND 1000;

SELECT AVG(capacity_mwh) AS average_capacity
FROM production_sites
WHERE status = 'active';

SELECT site_name, location, capacity_mwh, status
FROM production_sites
ORDER BY capacity_mwh DESC;
